// ===== Performance Dashboard — Build data.json =====
// Unisce gli output dei 3 nodi HTTP e calcola i KPI macro.
// I valori *_target vanno presi da context/brand/financials/ — qui placeholder.

const shopify = $('Shopify · Orders 30gg').first().json;
const google  = $('Google Ads · GAQL 30gg').first().json;
const meta    = $('Meta Ads · Insights 30gg').first().json;

// --- TARGET (da context/brand/financials/) ---
const TARGETS = { mer: 4.0, ncac: 42 };

// --- SHOPIFY ---
const orders = (shopify.orders || []);
let revenue = 0, newC = 0, retC = 0;
for (const o of orders) {
  revenue += parseFloat(o.total_price || 0);
  const oc = (o.customer && o.customer.orders_count) || 1;
  if (oc <= 1) newC++; else retC++;
}
const ordersN = orders.length;
const aov = ordersN ? revenue / ordersN : 0;

// --- GOOGLE ---
const gCamps = [];
let gSpend = 0, gConv = 0, gVal = 0;
for (const batch of (Array.isArray(google) ? google : [google])) {
  for (const r of (batch.results || [])) {
    const spend = (r.metrics?.costMicros || 0) / 1e6;
    const conv = r.metrics?.conversions || 0;
    const val = r.metrics?.conversionsValue || 0;
    gSpend += spend; gConv += conv; gVal += val;
    const roas = spend ? val / spend : 0;
    gCamps.push({ name: r.campaign?.name, type: r.campaign?.advertisingChannelType,
      spend: Math.round(spend), conv: Math.round(conv), cpa: conv ? +(spend/conv).toFixed(1) : null,
      roas: +roas.toFixed(1), impression_share: r.metrics?.searchImpressionShare ?? null,
      status: roas >= 3 ? 'g' : roas >= 1.8 ? 'w' : 'b' });
  }
}

// --- META ---
const mCamps = [];
let mSpend = 0, mConv = 0, mVal = 0;
for (const r of (meta.data || [])) {
  const spend = parseFloat(r.spend || 0);
  const purch = (r.actions || []).find(a => a.action_type === 'purchase');
  const conv = purch ? parseFloat(purch.value) : 0;
  const pv = (r.action_values || []).find(a => a.action_type === 'purchase');
  const val = pv ? parseFloat(pv.value) : 0;
  mSpend += spend; mConv += conv; mVal += val;
  const roas = spend ? val / spend : 0;
  const freq = parseFloat(r.frequency || 0);
  mCamps.push({ name: r.campaign_name, objective: r.objective,
    spend: Math.round(spend), conv: Math.round(conv), cpa: conv ? +(spend/conv).toFixed(1) : null,
    roas: +roas.toFixed(1), cpm: +parseFloat(r.cpm || 0).toFixed(1), ctr: +(parseFloat(r.ctr || 0)/100).toFixed(4),
    freq: +freq.toFixed(1),
    status: (roas < 2 && spend > 2000) ? 'b' : (freq > 3 ? 'w' : 'g') });
}

// --- CALCULATED (macro) ---
const totalSpend = gSpend + mSpend;
const totalRevenue = revenue;
const mer = totalSpend ? +(totalRevenue / totalSpend).toFixed(1) : 0;
const attributedRev = gVal + mVal;
const blendedRoas = totalSpend ? +(attributedRev / totalSpend).toFixed(1) : 0;
const ncac = newC ? Math.round(totalSpend / newC) : null;
const newPct = ordersN ? Math.round(newC / ordersN * 100) : null;

const out = {
  last_updated: new Date().toISOString().slice(0, 16).replace('T', ' '),
  business_model: 'eCommerce',
  currency: '€',
  period: { label: 'Ultimi 30gg', start: $today.minus({ days: 30 }).toISODate(), end: $today.toISODate() },
  calculated: {
    mer, mer_target: TARGETS.mer,
    blended_roas: blendedRoas,
    total_spend: Math.round(totalSpend),
    total_revenue: Math.round(totalRevenue),
    ncac, ncac_target: TARGETS.ncac,
    new_customer_pct: newPct,
    aov: +aov.toFixed(0)
  },
  shopify: { revenue_total: Math.round(revenue), orders: ordersN, aov: +aov.toFixed(0),
    new_customers: newC, returning_customers: retC, daily: [] },
  google_ads: { spend: Math.round(gSpend), conversions: Math.round(gConv),
    roas: gSpend ? +(gVal/gSpend).toFixed(1) : 0, cpa: gConv ? +(gSpend/gConv).toFixed(1) : null, campaigns: gCamps },
  meta_ads: { spend: Math.round(mSpend), conversions: Math.round(mConv),
    roas: mSpend ? +(mVal/mSpend).toFixed(1) : 0, cpa: mConv ? +(mSpend/mConv).toFixed(1) : null,
    cpm: mCamps.length ? +(mCamps.reduce((s,c)=>s+c.cpm,0)/mCamps.length).toFixed(1) : 0,
    ctr: mCamps.length ? +(mCamps.reduce((s,c)=>s+c.ctr,0)/mCamps.length).toFixed(4) : 0, campaigns: mCamps }
};

return [{ json: out }];
